1	type Cell = [number, number];
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	const fromKey = (key: string): Cell => {
5	  const [x, y] = key.split(",");
6	  return [Number(x), Number(y)];
7	};
8	
9	export function nextGeneration(cells: Array<Cell>): Array<Cell> {
10	  const liveKeys = new Set(cells.map(toKey));
11	
12	  const neighborCounts = new Map<string, number>();
13	  for (const [x, y] of cells) {
14	    for (let dx = -1; dx <= 1; dx++) {
15	      for (let dy = -1; dy <= 1; dy++) {
16	        if (dx === 0 && dy === 0) continue;
17	        const key = toKey([x + dx, y + dy]);
18	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
19	      }
20	    }
21	  }
22	
23	  const result: Array<Cell> = [];
24	  for (const [key, count] of neighborCounts) {
25	    const survives = liveKeys.has(key) && count === 2;
26	    const isBorn = count === 3;
27	    if (survives || isBorn) {
28	      result.push(fromKey(key));
29	    }
30	  }
31	
32	  return result;
33	}
